# gateway/model_gateway.py
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Optional

@dataclass
class ModelRequest:
    system: str
    messages: list[dict]
    max_tokens: int = 2048
    temperature: float = 1.0

@dataclass
class ModelResponse:
    content: str
    input_tokens: int
    output_tokens: int
    model_id: str
    stop_reason: str

class ModelGateway(ABC):
    """Vendor-agnostic interface for text generation."""

    @abstractmethod
    def generate(self, request: ModelRequest) -> ModelResponse:
        ...

    @abstractmethod
    def health_check(self) -> bool:
        ...


# gateway/anthropic_gateway.py
import anthropic
from .model_gateway import ModelGateway, ModelRequest, ModelResponse

class AnthropicGateway(ModelGateway):
    def __init__(self, model: str = "claude-sonnet-5"):
        self.client = anthropic.Anthropic()
        self.model = model

    def generate(self, request: ModelRequest) -> ModelResponse:
        response = self.client.messages.create(
            model=self.model,
            system=request.system,
            messages=request.messages,
            max_tokens=request.max_tokens,
        )
        return ModelResponse(
            content=response.content[0].text,
            input_tokens=response.usage.input_tokens,
            output_tokens=response.usage.output_tokens,
            model_id=response.model,
            stop_reason=response.stop_reason,
        )

    def health_check(self) -> bool:
        try:
            self.generate(ModelRequest(
                system="",
                messages=[{"role": "user", "content": "ping"}],
                max_tokens=5,
            ))
            return True
        except Exception:
            return False

# scripts/check_lock_in.py — run in CI
# Fail if any file outside gateway/ imports anthropic SDK directly

import ast
import sys
from pathlib import Path

VENDOR_IMPORTS = {"anthropic", "openai", "cohere", "boto3"}  # add vendors as needed
GATEWAY_DIR = Path("gateway")

violations = []
for py_file in Path("src").rglob("*.py"):
    if py_file.is_relative_to(GATEWAY_DIR):
        continue  # gateway package may import vendor SDKs
    tree = ast.parse(py_file.read_text())
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            names = [a.name for a in node.names] if isinstance(node, ast.Import)                     else ([node.module] if node.module else [])
            for name in names:
                if any(name == v or name.startswith(v + ".") for v in VENDOR_IMPORTS):
                    violations.append(f"{py_file}:{node.lineno}: direct vendor import '{name}'")

if violations:
    print("LOCK-IN GATE FAILED — direct vendor SDK imports outside gateway/:")
    for v in violations:
        print(f"  {v}")
    sys.exit(1)
print(f"Lock-in check passed: no direct vendor imports outside gateway/")
